#include <stdio.h>
#include <string.h>

int minInsertions(const char *s) {
    int n = strlen(s);
    static short dp[5001][5001]; // short saves memory, values ≤ 5000
    for (int i = 0; i <= n; ++i) dp[i][0] = dp[0][i] = 0;
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (s[i-1] == s[n-j])
                dp[i][j] = dp[i-1][j-1] + 1;
            else
                dp[i][j] = dp[i-1][j] > dp[i][j-1] ? dp[i-1][j] : dp[i][j-1];
        }
    }
    return n - dp[n][n];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[5001];
        scanf("%5000s", s);
        printf("%d\n", minInsertions(s));
    }
    return 0;
}

