#include <bits/stdc++.h>
using namespace std;

int minInsertions(const string &s) {
    int n = s.size();
    vector<vector<short>> dp(n+1, vector<short>(n+1, 0));
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (s[i-1] == s[n-j])
                dp[i][j] = dp[i-1][j-1] + 1;
            else
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
        }
    }
    return n - dp[n][n];
}

