function minInsertions(s) {
    const n = s.length;
    const rev = s.split('').reverse().join('');
    let prev = new Uint16Array(n + 1);
    let cur = new Uint16Array(n + 1);
    for (let i = 1; i <= n; i++) {
        cur[0] = 0;
        for (let j = 1; j <= n; j++) {
            if (s[i-1] === rev[j-1]) {
                cur[j] = prev[j-1] + 1;
            } else {
                cur[j] = prev[j] > cur[j-1] ? prev[j] : cur[j-1];
            }
        }
        const tmp = prev; prev = cur; cur = tmp;
    }
    const lps = prev[n];
    return n - lps;
}
